		NEXT_PUBLIC_ROOT_WS_URL: string;
		NEXT_PUBLIC_WS_MAINTENANCE_ROOT: string;
		// Gestion magasin
		NEXT_PUBLIC_STORES_ROOT: string;
		NEXT_PUBLIC_CATALOG_PRODUCTS: string;
		NEXT_PUBLIC_CATALOG_CATEGORIES: string;
		NEXT_PUBLIC_STOCK_BALANCES: string;
		NEXT_PUBLIC_STOCK_MOVEMENTS: string;
		NEXT_PUBLIC_SALES_ROOT: string;
		NEXT_PUBLIC_SALES_DASHBOARD: string;
		NEXT_PUBLIC_ATTENDANCE_ROOT: string;
		NEXT_PUBLIC_ATTENDANCE_EMPLOYEES: string;
		NEXT_PUBLIC_NOTIFICATIONS: string;
		NEXT_PUBLIC_NOTIFICATION_PREFERENCES: string;
		NEXT_PUBLIC_NOTIFICATION_MARK_READ: string;
		NEXT_PUBLIC_NOTIFICATION_UNREAD_COUNT: string;
